sql:
SELECT description
FROM file_types
WHERE is_archive = 1 AND is_image = 0 AND is_document = 0;

SELECT COUNT(type_id) 
FROM file_types 
WHERE is_image = 1 AND is_document = 0 AND is_archive = 0;

SELECT description
FROM file_types
WHERE is_archive = 1;

SELECT ds.state_description, COUNT(*) AS state_count
FROM download_states ds
GROUP BY ds.state_description;

SELECT AVG(state_id) AS average_state_id
FROM download_states
WHERE is_final = 1;

SELECT type_id, mime_type, original_mime_type, description
FROM file_types
WHERE is_image = 0 AND is_archive = 0;

SELECT description AS file_type
FROM file_types
WHERE is_archive = 1 AND is_image = 1;

SELECT DISTINCT mime_type
FROM file_types
WHERE is_image = 1;

SELECT 
  (SELECT mime_type FROM file_types WHERE type_id = 0) AS file_mime_type,
  (SELECT state_description FROM download_states WHERE state_id = 0) AS download_state_description;

SELECT 
  COALESCE((SELECT description FROM file_types WHERE type_id = 1), 'File type not found') AS file_type_description,
  COALESCE((SELECT state_description FROM download_states WHERE state_id = 0), 'Download state not found') AS download_state_description;

SELECT 
  (SELECT COUNT(*) FROM file_types) AS file_types_count,
  (SELECT COUNT(*) FROM download_states) AS download_states_count;

SELECT ft.mime_type, ft.description, ds.state_description
FROM file_types ft, download_states ds
WHERE ft.is_image = 1 AND ds.is_final = 1;

SELECT DISTINCT mime_type 
FROM file_types 
WHERE is_image = 1 OR is_document = 1;

SELECT DISTINCT mime_type
FROM file_types
WHERE is_archive = 0 AND mime_type IS NOT NULL AND mime_type != '';

SELECT file_types.type_id
FROM file_types
WHERE file_types.mime_type LIKE 'image/%' AND file_types.is_image = 1;

SELECT description 
FROM file_types 
WHERE description = 'Binary data files';

SELECT COUNT(*)
FROM file_types
WHERE is_archive = 1 AND mime_type = 'application/octet-stream';

SELECT f.mime_type, f.original_mime_type, f.description
FROM file_types f
WHERE f.is_image = 1;

SELECT AVG(state_id) AS AverageStateID
FROM download_states
WHERE is_final = 1;

SELECT COUNT(*) AS archive_document_count
FROM file_types
WHERE is_document = 1 AND is_archive = 1;

SELECT MIN(type_id)
FROM file_types
WHERE is_image = 1 AND is_archive = 1;

SELECT 
    (SELECT COUNT(*) FROM file_types) AS file_type_count,
    (SELECT COUNT(*) FROM download_states WHERE state_description = 'Completed') AS completed_download_count;

SELECT 
    (SELECT COUNT(*) FROM file_types) AS total_file_types,
    (SELECT COUNT(*) FROM download_states) AS total_download_states;

SELECT state_description 
FROM download_states 
WHERE is_final = 0;

SELECT description
FROM file_types
WHERE is_image = 0;

SELECT mime_type 
FROM file_types 
WHERE type_id = 1 AND is_image = 1 AND is_document = 0 AND is_archive = 0;
